current_file = ''
modified = False

def on_load_frmMain():
    global current_file, modified
    current_file = ''
    modified = False
    frmMain.title = 'Notepad - Untitled'
    update_status()

def update_status():
    text = txtEditor.caption
    lines = text.split('\n') if text else ['']
    words = len(text.split()) if text.strip() else 0
    chars = len(text)
    line_num = txtEditor.cursor_y + 1
    col_num = txtEditor.cursor_x + 1
    lblStatus.caption = f'Ln {line_num}, Col {col_num} | {len(lines)} lines | {words} words | {chars} chars'
    global modified
    if text:
        modified = True

def on_menu_mnuNew():
    global current_file, modified
    if modified and len(txtEditor.caption) > 0:
        result = msgbox('Save changes?', 'Confirm', 'yesnocancel')
        if result == 'yes':
            on_menu_mnuSave()
        elif result == 'cancel':
            return
    txtEditor.caption = ''
    current_file = ''
    modified = False
    frmMain.title = 'Notepad - Untitled'
    update_status()

def on_menu_mnuOpen():
    global current_file, modified
    if modified and len(txtEditor.caption) > 0:
        result = msgbox('Save changes?', 'Confirm', 'yesnocancel')
        if result == 'yes':
            on_menu_mnuSave()
        elif result == 'cancel':
            return

    filename = file_dialog('open', ['.txt', '.py', '.bas', '*'])
    if filename:
        handle = open_file(filename, 'r')
        if handle:
            lines = []
            line = read_line(handle)
            while line is not None:
                lines.append(line)
                line = read_line(handle)
            close_file(handle)
            txtEditor.caption = '\n'.join(lines)
            current_file = filename
            modified = False
            frmMain.title = f'Notepad - {filename}'
            update_status()
            msgbox(f'Loaded {len(lines)} lines', 'Open')

def on_menu_mnuSave():
    global current_file
    if current_file == '':
        on_menu_mnuSaveAs()
    else:
        save_current_file()

def on_menu_mnuSaveAs():
    global current_file
    filename = file_dialog('save', ['.txt', '.py', '.bas'])
    if filename:
        if '.' not in filename:
            filename = filename + '.txt'
        if file_exists(filename):
            result = msgbox(f'Overwrite {filename}?', 'Confirm', 'yesno')
            if result != 'yes':
                return
        current_file = filename
        save_current_file()

def save_current_file():
    global current_file, modified
    handle = open_file(current_file, 'w')
    if handle:
        lines = txtEditor.caption.split('\n')
        for line in lines:
            write_line(handle, line)
        close_file(handle)
        modified = False
        frmMain.title = f'Notepad - {current_file}'
        msgbox('File saved!', 'Save')

def on_menu_mnuExit():
    global modified
    if modified and len(txtEditor.caption) > 0:
        result = msgbox('Save changes before exit?', 'Confirm', 'yesnocancel')
        if result == 'yes':
            on_menu_mnuSave()
        elif result == 'cancel':
            return
    exit()

def on_menu_mnuCut():
    selected = txtEditor.get_selected_text() if hasattr(txtEditor, 'get_selected_text') else ''
    if selected:
        clipboard_set(selected)
        # Delete selected text
        txtEditor.caption = txtEditor.caption.replace(selected, '', 1)
        update_status()

def on_menu_mnuCopy():
    selected = txtEditor.get_selected_text() if hasattr(txtEditor, 'get_selected_text') else ''
    if selected:
        clipboard_set(selected)

def on_menu_mnuPaste():
    text = clipboard_get()
    if text:
        txtEditor.caption = txtEditor.caption + text
        update_status()

def on_menu_mnuFind():
    search_term = inputbox('Find:', 'Find', '')
    if search_term:
        pos = txtEditor.caption.find(search_term)
        if pos >= 0:
            msgbox(f'Found at position {pos}', 'Find')
        else:
            msgbox(f'"{search_term}" not found', 'Find')

def on_menu_mnuSelectAll():
    # Select all text
    txtEditor.cursor_x = 0
    txtEditor.cursor_y = 0
    # In a real implementation, this would select all text
    msgbox('Select All - All text selected', 'Edit')
